'use strict';
const http = require('http');

function createServer(routes = {}, options = {}) {
  const { port = 3000, cors = true } = options;

  const server = http.createServer(async (req, res) => {
    if (cors) {
      res.setHeader('Access-Control-Allow-Origin', '*');
      res.setHeader('Access-Control-Allow-Methods', 'GET,POST,PUT,DELETE,OPTIONS');
      res.setHeader('Access-Control-Allow-Headers', 'Content-Type,Authorization');
      if (req.method === 'OPTIONS') { res.writeHead(204); res.end(); return; }
    }

    const url = new URL(req.url, 'http://localhost');
    const key = req.method + ' ' + url.pathname;
    const handler = routes[key] || routes[req.method + ' *'];

    if (!handler) {
      res.writeHead(404, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Not Found', path: url.pathname }));
      return;
    }

    try {
      let body = null;
      if (['POST', 'PUT', 'PATCH'].includes(req.method)) {
        body = await readBody(req);
        try { body = JSON.parse(body); } catch {}
      }
      const result = await handler({ url, body, headers: req.headers, query: Object.fromEntries(url.searchParams) });
      const status = result?.status || 200;
      const data = result?.body ?? result;
      res.writeHead(status, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(data));
    } catch (err) {
      const status = err.status || 500;
      res.writeHead(status, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: err.message }));
    }
  });

  function readBody(req) {
    return new Promise((resolve, reject) => {
      let data = '';
      req.on('data', c => { data += c; if (data.length > 1e6) reject(new Error('Body too large')); });
      req.on('end', () => resolve(data));
      req.on('error', reject);
    });
  }

  return { server, listen: () => new Promise(r => server.listen(port, () => r(port))), close: () => server.close() };
}

module.exports = { createServer };

