'use strict';

class Schema {
  constructor(type, checks = []) { this._type = type; this._checks = checks; this._optional = false; }

  optional() { const s = this._clone(); s._optional = true; return s; }

  validate(value) {
    if (value === undefined || value === null) {
      if (this._optional) return { valid: true, data: value, errors: [] };
      return { valid: false, data: value, errors: ['Value is required'] };
    }
    const errors = [];
    for (const check of this._checks) {
      const err = check(value);
      if (err) errors.push(err);
    }
    return { valid: errors.length === 0, data: value, errors };
  }

  _clone() { const s = new Schema(this._type, [...this._checks]); s._optional = this._optional; return s; }
}

function string(opts = {}) {
  const s = new Schema('string', [(v) => typeof v !== 'string' ? 'Expected string' : null]);
  if (opts.min) s._checks.push(v => typeof v === 'string' && v.length < opts.min ? 'Too short (min ' + opts.min + ')' : null);
  if (opts.max) s._checks.push(v => typeof v === 'string' && v.length > opts.max ? 'Too long (max ' + opts.max + ')' : null);
  if (opts.pattern) s._checks.push(v => typeof v === 'string' && !opts.pattern.test(v) ? 'Pattern mismatch' : null);
  return s;
}

function number(opts = {}) {
  const s = new Schema('number', [(v) => typeof v !== 'number' || isNaN(v) ? 'Expected number' : null]);
  if (opts.min !== undefined) s._checks.push(v => typeof v === 'number' && v < opts.min ? 'Below min ' + opts.min : null);
  if (opts.max !== undefined) s._checks.push(v => typeof v === 'number' && v > opts.max ? 'Above max ' + opts.max : null);
  if (opts.integer) s._checks.push(v => typeof v === 'number' && !Number.isInteger(v) ? 'Expected integer' : null);
  return s;
}

function boolean() { return new Schema('boolean', [(v) => typeof v !== 'boolean' ? 'Expected boolean' : null]); }

function object(shape) {
  return new Schema('object', [(value) => {
    if (typeof value !== 'object' || value === null || Array.isArray(value)) return 'Expected object';
    for (const [key, schema] of Object.entries(shape)) {
      const result = schema.validate(value[key]);
      if (!result.valid) return key + ': ' + result.errors[0];
    }
    return null;
  }]);
}

function array(itemSchema, opts = {}) {
  const s = new Schema('array', [(value) => {
    if (!Array.isArray(value)) return 'Expected array';
    for (let i = 0; i < value.length; i++) {
      const r = itemSchema.validate(value[i]);
      if (!r.valid) return '[' + i + ']: ' + r.errors[0];
    }
    return null;
  }]);
  if (opts.min) s._checks.push(v => Array.isArray(v) && v.length < opts.min ? 'Array too short' : null);
  if (opts.max) s._checks.push(v => Array.isArray(v) && v.length > opts.max ? 'Array too long' : null);
  return s;
}

module.exports = { Schema, string, number, boolean, object, array };

