'use strict';

const LEVELS = { debug: 0, info: 1, warn: 2, error: 3 };

class Logger {
  constructor(opts = {}) {
    this._level = LEVELS[opts.level || 'info'] ?? 1;
    this._context = opts.context || {};
    this._output = opts.output || process.stdout;
    this._correlationId = opts.correlationId || null;
  }

  child(context) {
    return new Logger({
      level: Object.keys(LEVELS).find(k => LEVELS[k] === this._level),
      context: { ...this._context, ...context },
      output: this._output,
      correlationId: this._correlationId,
    });
  }

  setCorrelationId(id) { this._correlationId = id; return this; }

  debug(msg, data) { this._log('debug', msg, data); }
  info(msg, data) { this._log('info', msg, data); }
  warn(msg, data) { this._log('warn', msg, data); }
  error(msg, data) { this._log('error', msg, data); }

  _log(level, msg, data = {}) {
    if (LEVELS[level] < this._level) return;
    const entry = {
      timestamp: new Date().toISOString(),
      level,
      msg,
      ...this._context,
      ...data,
    };
    if (this._correlationId) entry.correlationId = this._correlationId;
    this._output.write(JSON.stringify(entry) + '
');
  }
}

function createLogger(opts) { return new Logger(opts); }

module.exports = { Logger, createLogger, LEVELS };

