'use strict';

function encodeCursor(value) {
  return Buffer.from(JSON.stringify(value)).toString('base64url');
}

function decodeCursor(cursor) {
  try { return JSON.parse(Buffer.from(cursor, 'base64url').toString()); }
  catch { return null; }
}

function paginate(items, options = {}) {
  const { cursor, limit = 20, direction = 'forward' } = options;
  const maxLimit = Math.min(Math.max(1, limit), 100);

  let startIdx = 0;
  if (cursor) {
    const decoded = decodeCursor(cursor);
    if (decoded && decoded.idx !== undefined) {
      startIdx = direction === 'forward' ? decoded.idx + 1 : Math.max(0, decoded.idx - maxLimit);
    }
  }

  const slice = items.slice(startIdx, startIdx + maxLimit + 1);
  const hasMore = slice.length > maxLimit;
  const data = hasMore ? slice.slice(0, maxLimit) : slice;

  const nextCursor = hasMore ? encodeCursor({ idx: startIdx + maxLimit - 1 }) : null;
  const prevCursor = startIdx > 0 ? encodeCursor({ idx: startIdx - 1 }) : null;

  return { data, nextCursor, prevCursor, hasMore, total: items.length };
}

module.exports = { encodeCursor, decodeCursor, paginate };

