'use strict';

const STATES = { CLOSED: 'closed', OPEN: 'open', HALF_OPEN: 'half_open' };

class CircuitBreaker {
  constructor(opts = {}) {
    this._threshold = opts.threshold || 5;
    this._cooldownMs = opts.cooldownMs || 30000;
    this._state = STATES.CLOSED;
    this._failures = 0;
    this._lastFailure = 0;
    this._successes = 0;
    this._totalCalls = 0;
  }

  get state() { return this._state; }
  get failures() { return this._failures; }

  async call(fn) {
    this._totalCalls++;

    if (this._state === STATES.OPEN) {
      if (Date.now() - this._lastFailure >= this._cooldownMs) {
        this._state = STATES.HALF_OPEN;
      } else {
        throw new Error('Circuit is OPEN — call rejected');
      }
    }

    try {
      const result = await fn();
      this._onSuccess();
      return result;
    } catch (err) {
      this._onFailure();
      throw err;
    }
  }

  _onSuccess() {
    this._failures = 0;
    this._successes++;
    if (this._state === STATES.HALF_OPEN) {
      this._state = STATES.CLOSED;
    }
  }

  _onFailure() {
    this._failures++;
    this._lastFailure = Date.now();
    if (this._failures >= this._threshold) {
      this._state = STATES.OPEN;
    }
  }

  reset() { this._state = STATES.CLOSED; this._failures = 0; }

  stats() {
    return { state: this._state, failures: this._failures, successes: this._successes, totalCalls: this._totalCalls };
  }
}

module.exports = { CircuitBreaker, STATES };

