'use strict';

async function retry(fn, options = {}) {
  const { attempts = 3, baseDelay = 1000, maxDelay = 30000, jitter = true, signal = null, onRetry = null } = options;

  let lastError;
  for (let attempt = 0; attempt < attempts; attempt++) {
    if (signal?.aborted) throw new Error('Aborted');

    try {
      return await fn(attempt);
    } catch (err) {
      lastError = err;
      if (attempt >= attempts - 1) break;

      let delay = Math.min(baseDelay * Math.pow(2, attempt), maxDelay);
      if (jitter) delay = delay * (0.5 + Math.random() * 0.5);

      if (onRetry) onRetry({ attempt, error: err, nextDelay: delay });

      await new Promise((resolve, reject) => {
        const timer = setTimeout(resolve, delay);
        if (signal) signal.addEventListener('abort', () => { clearTimeout(timer); reject(new Error('Aborted')); }, { once: true });
      });
    }
  }
  throw lastError;
}

module.exports = { retry };

