'use strict';

class EventBus {
  constructor() { this._listeners = new Map(); }

  on(event, fn) {
    if (!this._listeners.has(event)) this._listeners.set(event, []);
    this._listeners.get(event).push({ fn, once: false });
    return () => this.off(event, fn);
  }

  once(event, fn) {
    if (!this._listeners.has(event)) this._listeners.set(event, []);
    this._listeners.get(event).push({ fn, once: true });
    return () => this.off(event, fn);
  }

  off(event, fn) {
    const list = this._listeners.get(event);
    if (!list) return;
    this._listeners.set(event, list.filter(l => l.fn !== fn));
  }

  emit(event, ...args) {
    const list = this._listeners.get(event);
    if (!list) return;
    const remaining = [];
    for (const listener of list) {
      listener.fn(...args);
      if (!listener.once) remaining.push(listener);
    }
    this._listeners.set(event, remaining);
  }

  waitFor(event, timeoutMs = 5000) {
    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => { this.off(event, handler); reject(new Error('Timeout waiting for ' + event)); }, timeoutMs);
      const handler = (...args) => { clearTimeout(timer); resolve(args.length === 1 ? args[0] : args); };
      this.once(event, handler);
    });
  }

  listenerCount(event) { return (this._listeners.get(event) || []).length; }
  clear() { this._listeners.clear(); }
}

module.exports = { EventBus };

