'use strict';

class MiddlewareChain {
  constructor() { this._stack = []; }

  use(fn) { this._stack.push(fn); return this; }

  async handle(ctx) {
    let idx = 0;
    const next = async () => {
      if (idx >= this._stack.length) return;
      const fn = this._stack[idx++];
      await fn(ctx, next);
    };
    await next();
    return ctx;
  }

  compose(...chains) {
    const merged = new MiddlewareChain();
    merged._stack = [...this._stack];
    for (const chain of chains) {
      merged._stack.push(...(chain._stack || []));
    }
    return merged;
  }
}

function createChain() { return new MiddlewareChain(); }

module.exports = { MiddlewareChain, createChain };

